// ============================================
// URL LIST - Add your URLs to monitor here
// ============================================
// Each item needs:
//   name: A friendly label for alerts
//   url: The full URL to monitor
//   selector: (optional) CSS-like keyword to focus on specific content
// ============================================

const urlsToMonitor = [
  {
    name: 'Example - n8n Pricing',
    url: 'https://n8n.io/pricing/',
    selector: 'pricing'
  },
  {
    name: 'Example - GitHub Trending',
    url: 'https://github.com/trending',
    selector: ''
  },
  {
    name: 'Example - Hacker News',
    url: 'https://news.ycombinator.com/',
    selector: ''
  }
  // Add more URLs here:
  // {
  //   name: 'Competitor Pricing Page',
  //   url: 'https://competitor.com/pricing',
  //   selector: 'price'
  // },
];

return urlsToMonitor.map(item => ({ json: item }));

// ============================================
// CONTENT EXTRACTOR
// Strips HTML, extracts clean text + metadata
// ============================================

const urlData = $('📋 URL List').item.json;
const rawResponse = $json;

let rawHtml = '';
if (typeof rawResponse === 'string') {
  rawHtml = rawResponse;
} else if (rawResponse.data) {
  rawHtml = String(rawResponse.data);
} else if (rawResponse.body) {
  rawHtml = String(rawResponse.body);
} else {
  rawHtml = JSON.stringify(rawResponse);
}

// Extract metadata
let pageTitle = '';
let metaDescription = '';

try {
  const titleMatch = rawHtml.match(/<title[^>]*>([^<]+)<\/title>/i);
  pageTitle = titleMatch ? titleMatch[1].trim() : '';

  const metaMatch = rawHtml.match(/<meta[^>]*name=["']description["'][^>]*content=["']([^"']+)["']/i)
    || rawHtml.match(/<meta[^>]*content=["']([^"']+)["'][^>]*name=["']description["']/i);
  metaDescription = metaMatch ? metaMatch[1].trim() : '';
} catch (e) {}

// Strip HTML to get clean text
let cleanText = rawHtml
  // Remove script and style blocks entirely
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<noscript[^>]*>[\s\S]*?<\/noscript>/gi, '')
  // Remove SVG blocks
  .replace(/<svg[^>]*>[\s\S]*?<\/svg>/gi, '')
  // Remove navigation and footer (usually noise)
  .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, ' [NAV] ')
  .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, ' [FOOTER] ')
  // Convert block elements to newlines
  .replace(/<\/(div|p|h[1-6]|li|tr|section|article|blockquote)>/gi, '\n')
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<hr\s*\/?>/gi, '\n---\n')
  // Remove remaining HTML tags
  .replace(/<[^>]+>/g, ' ')
  // Decode HTML entities
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  .replace(/&#x27;/g, "'")
  .replace(/&#x2F;/g, '/')
  // Clean whitespace
  .replace(/[ \t]+/g, ' ')           // Collapse horizontal whitespace
  .replace(/\n\s*\n\s*\n/g, '\n\n')  // Max 2 newlines
  .replace(/^\s+|\s+$/gm, '')        // Trim each line
  .trim();

// If selector keyword is provided, try to focus on relevant content
const selector = urlData.selector || '';
let focusedContent = cleanText;

if (selector) {
  const lines = cleanText.split('\n');
  const relevantLines = [];
  let capturing = false;
  let captureCount = 0;

  for (const line of lines) {
    if (line.toLowerCase().includes(selector.toLowerCase())) {
      capturing = true;
      captureCount = 0;
    }
    if (capturing) {
      relevantLines.push(line);
      captureCount++;
      if (captureCount > 50) capturing = false; // Capture 50 lines after keyword
    }
  }

  if (relevantLines.length > 0) {
    focusedContent = relevantLines.join('\n');
  }
}

// Generate content hash for quick comparison
let contentHash = 0;
const hashInput = focusedContent.substring(0, 10000);
for (let i = 0; i < hashInput.length; i++) {
  const char = hashInput.charCodeAt(i);
  contentHash = ((contentHash << 5) - contentHash) + char;
  contentHash = contentHash & contentHash; // Convert to 32-bit integer
}
contentHash = Math.abs(contentHash).toString(36);

return {
  json: {
    // URL info
    name: urlData.name,
    url: urlData.url,
    selector: selector,

    // Extracted content
    pageTitle: pageTitle,
    metaDescription: metaDescription,
    cleanText: focusedContent.substring(0, 50000), // Limit storage size
    contentHash: contentHash,
    contentLength: focusedContent.length,

    // Metadata
    fetchedAt: new Date().toISOString(),
    httpStatus: rawResponse.statusCode || rawResponse.status || 200
  }
};

// ============================================
// DIFF ENGINE
// Compare current vs previous, generate diff
// ============================================

const currentData = $('📄 Extract Content').item.json;
const allPreviousRows = $('📋 Load Previous Snapshot').all();

// Find the previous snapshot for this specific URL
let previousContent = '';
let previousHash = '';
let lastChecked = '';
let isFirstRun = true;

for (const row of allPreviousRows) {
  const rowUrl = (row.json.URL || row.json.url || '').trim();
  if (rowUrl === currentData.url) {
    previousContent = row.json.Content || row.json.content || '';
    previousHash = row.json['Content Hash'] || row.json.contentHash || '';
    lastChecked = row.json['Last Checked'] || row.json.lastChecked || '';
    isFirstRun = false;
    break;
  }
}

// Quick hash comparison first
if (!isFirstRun && previousHash === currentData.contentHash) {
  return {
    json: {
      ...currentData,
      hasChanged: false,
      isFirstRun: false,
      changePercentage: 0,
      diffSummary: 'No changes detected.',
      addedLines: [],
      removedLines: [],
      lastChecked: lastChecked,
      comparedAt: new Date().toISOString()
    }
  };
}

// If first run, save baseline
if (isFirstRun) {
  return {
    json: {
      ...currentData,
      hasChanged: false,
      isFirstRun: true,
      changePercentage: 0,
      diffSummary: 'First run — baseline snapshot saved. Changes will be detected from the next run.',
      addedLines: [],
      removedLines: [],
      lastChecked: 'Never',
      comparedAt: new Date().toISOString()
    }
  };
}

// ============================================
// DETAILED DIFF COMPARISON
// ============================================

const prevLines = previousContent.split('\n').map(l => l.trim()).filter(l => l.length > 0);
const currLines = currentData.cleanText.split('\n').map(l => l.trim()).filter(l => l.length > 0);

// Build sets for comparison
const prevSet = new Set(prevLines);
const currSet = new Set(currLines);

// Find added lines (in current but not in previous)
const addedLines = currLines.filter(line => !prevSet.has(line));

// Find removed lines (in previous but not in current)
const removedLines = prevLines.filter(line => !currSet.has(line));

// Calculate change percentage
const totalLines = Math.max(prevLines.length, currLines.length, 1);
const changedLines = addedLines.length + removedLines.length;
const changePercentage = Math.round((changedLines / totalLines) * 100);

// Generate human-readable diff summary
let diffSummary = '';

if (addedLines.length > 0) {
  diffSummary += `\n➕ ADDED (${addedLines.length} lines):\n`;
  addedLines.slice(0, 20).forEach(line => {
    diffSummary += `  + ${line.substring(0, 200)}\n`;
  });
  if (addedLines.length > 20) {
    diffSummary += `  ... and ${addedLines.length - 20} more added lines\n`;
  }
}

if (removedLines.length > 0) {
  diffSummary += `\n➖ REMOVED (${removedLines.length} lines):\n`;
  removedLines.slice(0, 20).forEach(line => {
    diffSummary += `  - ${line.substring(0, 200)}\n`;
  });
  if (removedLines.length > 20) {
    diffSummary += `  ... and ${removedLines.length - 20} more removed lines\n`;
  }
}

if (!diffSummary) {
  diffSummary = 'Hash changed but no line-level differences detected (possible whitespace or formatting change).';
}

// Determine change severity
let severity = 'low';
if (changePercentage > 50) severity = 'critical';
else if (changePercentage > 20) severity = 'high';
else if (changePercentage > 5) severity = 'medium';

return {
  json: {
    ...currentData,
    hasChanged: true,
    isFirstRun: false,
    changePercentage: changePercentage,
    severity: severity,
    diffSummary: diffSummary.trim(),
    addedCount: addedLines.length,
    removedCount: removedLines.length,
    addedLines: addedLines.slice(0, 30),
    removedLines: removedLines.slice(0, 30),
    previousContentLength: previousContent.length,
    currentContentLength: currentData.cleanText.length,
    lastChecked: lastChecked,
    comparedAt: new Date().toISOString()
  }
};

