={{ (() => {
const d = $json;
const severityEmoji = {
  'critical': '🔴',
  'high': '🟠',
  'medium': '🟡',
  'low': '🟢'
};
const emoji = severityEmoji[d.severity] || '🔵';

let msg = `${emoji} *WEBSITE CHANGE DETECTED*\n\n`;
msg += `📄 *${d.name}*\n`;
msg += `🔗 ${d.url}\n\n`;
msg += `📊 *Change: ${d.changePercentage}%* (${d.severity})\n`;
msg += `➕ ${d.addedCount || 0} lines added\n`;
msg += `➖ ${d.removedCount || 0} lines removed\n\n`;
msg += `📝 *Diff Summary:*\n`;
msg += '```\n';
msg += (d.diffSummary || 'No details').substring(0, 2000);
msg += '\n```\n\n';
msg += `⏰ Detected: ${d.comparedAt}\n`;
msg += `📅 Last checked: ${d.lastChecked}`;

return msg;
})() }}

