parameters.jsCode:
// Log entry for change history
const d = $json;

return {
  json: {
    status: d.isFirstRun ? 'baseline_saved' : (d.hasChanged ? 'change_detected' : 'no_change'),
    url: d.url,
    name: d.name,
    changePercentage: d.changePercentage || 0,
    severity: d.severity || 'none',
    addedCount: d.addedCount || 0,
    removedCount: d.removedCount || 0,
    checkedAt: d.fetchedAt,
    message: d.isFirstRun 
      ? `✅ Baseline saved for ${d.name}` 
      : (d.hasChanged 
        ? `🔄 ${d.changePercentage}% change detected on ${d.name}` 
        : `✓ No changes on ${d.name}`)
  }
};
